+// ---------------------------------------------------------------------------
+
+export type WorkerRequest =
+  | { id: number; type: 'get'; key: string }
+  | { id: number; type: 'set'; key: string; entry: CacheEntry }
+  | { id: number; type: 'delete'; key: string }
+  | { id: number; type: 'clear' }
+  | { id: number; type: 'getStats' }
